import{_ as r,o as a,c as o,ae as e}from"./chunks/framework.BeMCGcrk.js";const p=JSON.parse('{"title":"小米集团(01810.HK)行情分析 | 2026年6月30日","description":"","frontmatter":{},"headers":[],"relativePath":"blog/2026-06-30-15.md","filePath":"blog/2026-06-30-15.md"}'),l={name:"blog/2026-06-30-15.md"};function d(n,t,i,s,h,g){return a(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="小米集团-01810-hk-行情分析-2026年6月30日" tabindex="-1">小米集团(01810.HK)行情分析 | 2026年6月30日 <a class="header-anchor" href="#小米集团-01810-hk-行情分析-2026年6月30日" aria-label="Permalink to &quot;小米集团(01810.HK)行情分析 | 2026年6月30日&quot;">​</a></h1><h2 id="今日行情快照" tabindex="-1">今日行情快照 <a class="header-anchor" href="#今日行情快照" aria-label="Permalink to &quot;今日行情快照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>最新价</td><td><strong>21.58 HKD</strong></td></tr><tr><td>涨跌幅</td><td>-0.28 (-1.28%)</td></tr><tr><td>今开</td><td>21.86</td></tr><tr><td>最高</td><td>22.10</td></tr><tr><td>最低</td><td>21.34</td></tr><tr><td>成交量</td><td>1.05亿股</td></tr><tr><td>52周最高</td><td>59.90</td></tr><tr><td>52周最低</td><td>22.50</td></tr></tbody></table><blockquote><p>数据来源：腾讯财经实时行情（15:02更新）</p></blockquote><hr><h2 id="操作建议-观望" tabindex="-1">操作建议：<strong>观望</strong> <a class="header-anchor" href="#操作建议-观望" aria-label="Permalink to &quot;操作建议：**观望**&quot;">​</a></h2><h3 id="持仓状态" tabindex="-1">持仓状态 <a class="header-anchor" href="#持仓状态" aria-label="Permalink to &quot;持仓状态&quot;">​</a></h3><ul><li><strong>持仓：</strong> 2800股</li><li><strong>成本价：</strong> 33.99 HKD</li><li><strong>当前价：</strong> 21.58 HKD</li><li><strong>浮动亏损：</strong> 约 <strong>34,748 HKD</strong>（-36.5%）</li><li><strong>止损价：</strong> 33.50 HKD</li></ul><h3 id="分析依据" tabindex="-1">分析依据 <a class="header-anchor" href="#分析依据" aria-label="Permalink to &quot;分析依据&quot;">​</a></h3><p><strong>技术面：极度超卖，但无企稳信号</strong></p><p>当前股价21.58港元已跌破52周最低点22.50，创下新低。6月29日曾反弹至21.86港元，但今日再度回落，成交量维持高位（超1亿股），显示多空博弈激烈，尚无明确方向。</p><p><strong>基本面：业绩承压，估值逻辑松动</strong></p><ul><li>2026年Q1营收991亿元，同比下滑10.9%，经调整净利润同比暴跌43.1%</li><li>手机基本盘增长见顶，AIoT增量有限</li><li>汽车业务持续烧钱，尚未实现盈利</li><li>机构目标价普遍在38-51港元，但短期无催化剂</li></ul><p><strong>资金面：回购托底，但力度不足</strong></p><p>公司6月持续回购（每日300-800万股，回购价24-27港元区间），但未能阻止股价下行。主力资金近两日出现分化信号。</p><h3 id="操作逻辑" tabindex="-1">操作逻辑 <a class="header-anchor" href="#操作逻辑" aria-label="Permalink to &quot;操作逻辑&quot;">​</a></h3><p>当前价位距离止损价（33.50）仍有较大空间，但距离成本价（33.99）更远，<strong>深度套牢已成事实</strong>。此时：</p><ul><li><strong>不加仓</strong> — 趋势未反转，加仓只会扩大亏损</li><li><strong>不减仓</strong> — 当前位置割肉意义不大，且公司有回购托底</li><li><strong>观望</strong> — 等技术面出现底部企稳信号（如连续3日站上5日线）再考虑加仓摊薄成本</li></ul><hr><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><p>本文仅为个人记录，不构成投资建议。股市有风险，投资需谨慎。</p>',21)])])}const u=r(l,[["render",d]]);export{p as __pageData,u as default};
